const features = $input.first().json?.features || [];

const alerts = features.map(f => {
  const p = f.properties || {};
  const c = f.geometry?.coordinates || [0, 0, 0];
  const mag = p.mag || 0;

  let severity = 'green';
  if (mag >= 7.0) severity = 'red';
  else if (mag >= 5.5) severity = 'orange';

  return {
    json: {
      title: `🌍 M${mag.toFixed(1)} Earthquake — ${p.place || 'Unknown'}`,
      summary: `Magnitude ${mag.toFixed(1)} at depth ${c[2]?.toFixed(1) || '?'}km. ${p.tsunami ? '⚠️ TSUNAMI WARNING' : 'No tsunami warning.'}`,
      source: 'USGS',
      source_url: p.url || 'https://earthquake.usgs.gov',
      image_url: null,
      severity: severity,
      event_type: 'earthquake',
      latitude: c[1],
      longitude: c[0],
      country: (p.place || '').split(', ').pop() || null,
      source_id: `usgs-${f.id}`
    }
  };
});

return alerts.length > 0 ? alerts : [{ json: { _skip: true } }];
